final:
module top_module(
    clk,
    Load,
    not_reset,
    D,
    Q
);input wire clk;
input wire not_reset;
input wire Load;
input wire [15:0] D;
output wire [15:0] Q;

reg [15:0] X_Q_ALTERA_SYNTHESIZED;

always @(posedge clk or negedge not_reset) begin
    if (!not_reset) begin
        X_Q_ALTERA_SYNTHESIZED <= 0;
    end else if (Load) begin
        X_Q_ALTERA_SYNTHESIZED <= D;
    end
end

assign Q = X_Q_ALTERA_SYNTHESIZED;

endmodule
